from collections.abc import Iterable


def flatten(seq):
    """Recursively flatten an arbitrarily nested sequence into a flat list."""
    result = []
    for item in seq:
        if isinstance(item, Iterable):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result


# >>> flatten([1, [2, [3, 4], 5], 6])
# [1, 2, 3, 4, 5, 6]
